// Find attachments matching the naming convention and not yet processed
// Convention: filename starts with 'attributes_completed_'
// We use n8n's static data to remember the last processed attachment UUID

const attachments = $input.first().json.response?.grid ?? [];

// Filter to files matching the naming pattern
const candidates = attachments.filter(a => {
  const name = (a.name ?? '').toLowerCase();
  return name.startsWith('attributes_completed_') && name.endsWith('.xlsx');
});

if (!candidates.length) {
  return [{ json: { skip: true, reason: 'No matching attachments found' } }];
}

// Sort newest first
candidates.sort((a, b) => new Date(b.created ?? 0) - new Date(a.created ?? 0));
const latest = candidates[0];

// Check if we already processed this one (stored in workflow static data)
const staticData = $getWorkflowStaticData('global');
const lastProcessed = staticData.lastProcessedUuid;

if (latest.uuid === lastProcessed) {
  return [{ json: { skip: true, reason: `Already processed: ${latest.name}` } }];
}

// New file — mark it and continue
staticData.lastProcessedUuid = latest.uuid;
staticData.lastProcessedAt   = new Date().toISOString();

return [{ json: {
  skip:     false,
  blobId:   latest.blobId,
  name:     latest.name,
  uuid:     latest.uuid
} }];

const rows = $input.all().map(i => i.json);
const langs = ['fr', 'es', 'de'];
const translations = {};

for (const row of rows) {
  const uuid = String(row['Hotspot UUID'] ?? '').trim();
  if (!uuid) continue;
  for (const lang of langs) {
    const title       = String(row[`${lang.toUpperCase()} Title`]       ?? '').trim();
    const description = String(row[`${lang.toUpperCase()} Description`] ?? '').trim();
    if (!title && !description) continue;
    if (!translations[lang]) translations[lang] = {};
    translations[lang][uuid] = { title, description };
  }
}

return [{ json: {
  productUuid: 'f047fcd9-eceb-465b-9abd-625efaa99ac2',
  org:         'DCicero',
  workspace:   'n8n-work',
  translations
} }];

const product    = $node['Get Product'].json.response;
const newTrans   = $node['Transform'].json.translations;
const attrMap    = {};

for (const a of (product.attributes ?? [])) {
  attrMap[a.name ?? a.key] = a.value;
}
for (const [lang, data] of Object.entries(newTrans)) {
  attrMap[`hotspot_translations_${lang}`] = JSON.stringify(data);
}

const attributes = Object.entries(attrMap).map(([name, value]) => ({ name, value }));
return [{ json: { uuid: product.uuid, name: product.name, attributes } }];
